import{_ as t,o as e,c as o,V as n}from"./chunks/framework.509d3f30.js";const p=JSON.parse('{"title":"Fraud events","description":"","frontmatter":{},"headers":[],"relativePath":"overview/fraud-events.md","filePath":"overview/fraud-events.md"}'),r={name:"overview/fraud-events.md"},a=n('<h1 id="fraud-events" tabindex="-1">Fraud events <a class="header-anchor" href="#fraud-events" aria-label="Permalink to &quot;Fraud events&quot;">​</a></h1><blockquote><p><strong>Fraud event</strong> — an occurrence that is suspected or confirmed to be fraudulent.</p></blockquote><p>FIB peers can submit data related to these fraud events—<a href="./contributions.html">contributions</a>—to help identify and prevent future fraudulent activities. By sharing information and collaborating with other participants in the network, contributors can help create a more secure and trustworthy ecosystem that is resistant to fraud and other types of malicious activities.</p><h2 id="fraud-model" tabindex="-1">Fraud model <a class="header-anchor" href="#fraud-model" aria-label="Permalink to &quot;Fraud model&quot;">​</a></h2><p>Every fraud event that is submitted and stored on the blockchain adheres to the following model:</p><table><thead><tr><th>Data</th><th>Description</th></tr></thead><tbody><tr><td>Fraud Identifier</td><td>The main identifier of the fraud event. <br> Could be one of the following: <ol><li>A range of <strong>phone numbers</strong> (or a single one) compliant with the E.164 international standard and containing a valid National Destination Code.</li><li>A range of <strong>IP addresses</strong> (or a single one).</li><li>A unique <strong>IMEI identifier</strong> of a device. </li></ol></td></tr><tr><td>Fraud Type</td><td>The type of the fraud event. <br> Could be one of the following: <ol><li><code>Wangiri</code></li><li><code>IRSF</code></li><li><code>StolenDevice</code></li><li><code>IPFraud</code></li><li><code>SMSA2P</code></li></ol></td></tr><tr><td>Event Origination</td><td>The two-digit code of the country the fraud event originated from (Alpha-2, ISO 3166).</td></tr><tr><td>Event Destination</td><td>The two-digit code of the country the fraud event was identified as such (Alpha-2, ISO 3166).</td></tr><tr><td>Event Status</td><td>The status of the event at the time of observing. <br> Could be one of the following: <ol><li><strong>Active</strong> — the event is stored on the blockchain and has not yet expired.</li><li><strong>Expired</strong> — the event is stored on the blockchain, but is no longer relevant.</li><li><strong>Flagged</strong> — the event is stored on the blockchain and is flagged by one of the peers.</li></ol></td></tr><tr><td>Event Expiry Date</td><td>The exact time and date until which the event is considered relevant.</td></tr><tr><td>Event Timestamp</td><td>The exact time and date of when the event was submitted.</td></tr><tr><td>Confidence Index</td><td>The predicted fraud likelihood score in the range from 1 to 100.</td></tr><tr><td>Consortium Identity Key</td><td>The unique key of the peer that contributed the data.</td></tr></tbody></table>',6),d=[a];function i(s,l,h,c,u,f){return e(),o("div",null,d)}const g=t(r,[["render",i]]);export{p as __pageData,g as default};
